output-schema.json-structure:
{
  "headline": "string (max 15 words)",
  "subheadline": "string (max 30 words)",
  "highlightMetric": {
    "value": "string (the number)",
    "label": "string (what the number represents)"
  }
}

examples.example:
{
  "headline": "Jusu konkurentai gauna 3,000 lankytoju per menesi is Google",
  "subheadline": "Musu analize parodo, kad plaukucentras.lt gali pasiekti ta pati srautu lygi per 6 menesius.",
  "highlightMetric": {
    "value": "24",
    "label": "greitos pergales raktazodziai"
  }
}

{
  "headline": "Your competitors get 3,000 visitors monthly from Google",
  "subheadline": "Our analysis shows example.com can reach the same traffic level within 6 months.",
  "highlightMetric": {
    "value": "24",
    "label": "quick win keywords"
  }
}
